    31→import { filterTools, getToolCategories, getToolCountByCategory } from '../utils/tool-filter.js';
    32→import { runWithSessionContext } from '../utils/execution-context.js';
    33→import { CONFIG } from '../server/config.js';
    34→
    35→/**
    36→ * Flag to track if tools have been initialized
    37→ */
    38→let toolsInitialized = false;
    39→
    40→/**
    41→ * Ensure tools are initialized before use
    42→ */
    43→async function ensureToolsInitialized(): Promise<void> {
    44→  if (!toolsInitialized) {
    45→    await initializeTools();
