    47→  }
    48→}
    49→
    50→/**
    51→ * Handles the list tools request.
    52→ * 
    53→ * @param _request - The list tools request (unused, but required by interface)
    54→ * @returns Promise that resolves to a list of available tools
    55→ */
    56→export async function handleListTools(_request: ListToolsRequest): Promise<ListToolsResult> {
    57→  try {
    58→    // Ensure tools are loaded
    59→    await ensureToolsInitialized();
    60→    
    61→    logger.info(`🔧 handleListTools called, TOOLS.length: ${TOOLS.length}`);
    62→    
    63→    // Check if tool filtering is enabled
    64→    if (CONFIG.TOOL_FILTER_ENABLED === true) {
    65→      const maxTools = CONFIG.MAX_TOOLS_PER_RESPONSE || 50;
    66→      const allowedCategories = CONFIG.ALLOWED_TOOL_CATEGORIES?.split(',').map(c => c.trim()).filter(Boolean);
    67→      
    68→      const filterOptions = {
    69→        maxTools,
    70→        categories: allowedCategories && allowedCategories.length > 0 ? allowedCategories : undefined,
    71→      };
    72→      
    73→      const result = filterTools(TOOLS, filterOptions);
    74→      
    75→      logger.info(`📊 Tool filtering enabled:`);
    76→      logger.info(`   Total tools: ${TOOLS.length}`);
    77→      logger.info(`   Filtered tools: ${result.tools.length}`);
    78→      logger.info(`   Max per response: ${maxTools}`);
    79→      if (allowedCategories?.length) {
    80→        logger.info(`   Allowed categories: ${allowedCategories.join(', ')}`);
    81→      }
    82→      
    83→      // Log category distribution
    84→      const categories = getToolCategories(result.tools);
    85→      const categoryCount = getToolCountByCategory(result.tools);
    86→      logger.info(`   Categories: ${categories.join(', ')}`);
    87→      logger.info(`   Category distribution: ${JSON.stringify(categoryCount)}`);
    88→      
    89→      return {
    90→        tools: result.tools,
    91→        nextCursor: result.nextCursor
    92→      };
    93→    } else {
    94→      // Return all tools without filtering
    95→      logger.info(`📊 Tool filtering disabled, returning all ${TOOLS.length} tools`);
    96→      return {
    97→        tools: TOOLS,
    98→      };
    99→    }
   100→  } catch (error) {
   101→    logger.error('Error in handleListTools:', error);
   102→    throw error;
   103→  }
   104→}
   105→
   106→/**
   107→ * Handles tool call requests using dynamic tool loading.
   108→ * 
   109→ * @param request - The tool call request
   110→ * @param context - The MCP tool context
   111→ * @returns Promise that resolves to the tool call result
   112→ */
   113→export async function handleToolCall(
   114→  request: CallToolRequest,
   115→  context: MCPToolContext,
   116→): Promise<CallToolResult> {
   117→  const toolName = request.params.name;
   118→  const end = toolDuration.startTimer({ tool_name: toolName });
   119→
   120→  try {
   121→    // Ensure tools are loaded
   122→    await ensureToolsInitialized();
   123→    
   124→    logger.info(`🔧 handleToolCall called for tool: ${request.params.name}`);
   125→    
   126→    // Create minimal context for tool handlers
   127→    const handlerContext: ToolHandlerContext = {
   128→      userId: 'cli-user',
   129→      sessionId: context.sessionId,
   130→      progressToken: request.params._meta?.progressToken,
   131→    };
   132→
   133→    // Validate arguments are provided
   134→    if (!request.params.arguments) {
   135→      const toolName = request.params?.name || 'unknown';
   136→      logger.error("Tool call missing required arguments", { toolName });
   137→      
   138→      // Provide helpful error message for specific tools
   139→      if (toolName === 'mittwald_domain_virtualhost_create') {
   140→        throw new Error("Arguments are required. Expected: { hostname: string, pathToApp?: string[], pathToUrl?: string[], pathToContainer?: string[] }. At least one path mapping is required. For containers use pathToContainer: ['/:c-xxxxx:port/tcp'].");
   141→      }
   142→      
   143→      throw new Error(`Arguments are required for tool '${toolName}'`);
   144→    }
   145→
   146→    // Check if tool exists
   147→    const tool = TOOLS.find((t) => t.name === request.params.name);
   148→    if (!tool) {
   149→      logger.error("Unknown tool requested", { toolName: request.params.name });
   150→      throw new Error(`${TOOL_ERROR_MESSAGES.UNKNOWN_TOOL} ${request.params.name}`);
   151→    }
   152→
   153→    // Get tool handler dynamically
   154→    const handler = await getToolHandler(request.params.name);
   155→    if (!handler) {
   156→      logger.error("No handler found for tool", { toolName: request.params.name });
   157→      throw new Error(`No handler found for tool: ${request.params.name}`);
   158→    }
   159→
   160→    // Get and validate schema if available
   161→    const schema = await getToolSchema(request.params.name);
   162→    if (schema && schema.properties) {
   163→      try {
   164→        // Convert JSON Schema properties to Zod schema
   165→        const zodSchemaProperties: { [key: string]: z.ZodType } = {};
   166→        
   167→        for (const [propName, propSchema] of Object.entries(schema.properties)) {
   168→          const prop = propSchema as any;
   169→          
   170→          // Create appropriate Zod type based on JSON schema type
   171→          switch (prop.type) {
   172→            case 'string':
   173→              if (prop.enum) {
   174→                zodSchemaProperties[propName] = z.enum(prop.enum);
   175→              } else {
   176→                zodSchemaProperties[propName] = z.string();
   177→              }
   178→              break;
   179→            case 'boolean':
   180→              zodSchemaProperties[propName] = z.boolean();
   181→              break;
   182→            case 'number':
   183→              zodSchemaProperties[propName] = z.number();
   184→              break;
   185→            case 'array':
   186→              zodSchemaProperties[propName] = z.array(z.string());
   187→              break;
   188→            default:
   189→              zodSchemaProperties[propName] = z.any();
   190→          }
   191→          
   192→          // Make optional if not required
   193→          if (!schema.required || !schema.required.includes(propName)) {
   194→            zodSchemaProperties[propName] = zodSchemaProperties[propName].optional();
   195→          }
   196→        }
   197→        
   198→        const zodSchema = z.object(zodSchemaProperties);
   199→        zodSchema.parse(request.params.arguments);
   200→      } catch (validationError) {
   201→        logger.error("Tool arguments validation failed", { 
   202→          toolName: request.params.name, 
   203→          error: validationError,
   204→          arguments: request.params.arguments
   205→        });
   206→        throw new Error(`Invalid arguments for tool '${request.params.name}': ${validationError}`);
   207→      }
   208→    }
   209→
   210→    // Execute the tool handler
   211→    logger.info(`🚀 Executing tool handler for ${request.params.name}`);
   212→    
   213→    // Check if this is a session-aware CLI tool (has session in the name)
   214→    const isSessionAware = request.params.name.includes('_session') || 
   215→                          request.params.name.includes('accessible_projects');
   216→    
   217→    let result: CallToolResult;
   218→    result = await runWithSessionContext(context.sessionId, () => handler(request.params.arguments as any));
   219→
   220→    toolCallsTotal.inc({ tool_name: toolName, status: 'success' });
   221→    end(); // Record duration
   222→    logger.info(`✅ Tool ${request.params.name} executed successfully`);
   223→    return result;
   224→    
   225→  } catch (error) {
   226→    toolCallsTotal.inc({ tool_name: toolName, status: 'error' });
   227→    end(); // Record duration even on error
   228→    logger.error(`❌ Tool ${request.params.name} failed:`, error);
   229→
   230→    // Return error result instead of throwing
   231→    return {
   232→      content: [
   233→        {
   234→          type: 'text',
   235→          text: `Error executing tool '${request.params.name}': ${error instanceof Error ? error.message : String(error)}`,
   236→        },
   237→      ],
   238→      isError: true,
   239→    };
   240→  }
   241→}
   242→
   243→/**
   244→ * Initialize the tool handlers system
   245→ * 
   246→ * @remarks
   247→ * This function should be called during server startup to ensure all tools are loaded
   248→ */
   249→export async function initializeToolHandlers(): Promise<void> {
   250→  try {
   251→    await ensureToolsInitialized();
   252→    logger.info('✅ Tool handlers system initialized successfully');
   253→  } catch (error) {
   254→    logger.error('❌ Failed to initialize tool handlers system:', error);
   255→    throw error;
   256→  }
   257→}
