import type { Dependency } from '../types/app-dependencies';

export function formatDependencyList(dependencies: Dependency[]): string {
  if (dependencies.length === 0) {
    return 'No dependencies found';
  }

  const rows = dependencies.map(dep => [
    dep.name,
    dep.currentVersion,
    dep.latestVersion,
    dep.type,
    dep.updateAvailable ? '✓' : ''
  ]);

  const tableHeaders = ['Name', 'Current Version', 'Latest Version', 'Type', 'Update Available'];
  const maxColumnWidths = tableHeaders.map((header, i) =>
    Math.max(...rows.map(row => row[i].toString().length), header.length)
  );

  const formattedRows = rows.map(row =>
    row.map((cell, i) => cell.toString().padEnd(maxColumnWidths[i]))
  );

  const formattedTable = [
    tableHeaders.map((header, i) => header.padEnd(maxColumnWidths[i])).join(' | '),
    '-'.repeat(tableHeaders.reduce((sum, header) => sum + header.length + 3, 0)),
    ...formattedRows.map(row => row.join(' | '))
  ].join('\n');

  return formattedTable;
}

